func findNode(id string, nodes []Node) *Node {
	for i := range nodes {
		if nodes[i].ID == id {
			return &nodes[i]
		}
	}
	return nil
}

func fmtF(f float64) string {
	return strconv.FormatFloat(f, 'f', 1, 64)
}

func svgHeight(nodes []Node) string {
	if len(nodes) == 0 {
		return "100"
	}
	return fmt.Sprintf("%.0f", nodes[len(nodes)-1].Y+60)
}

func nodeColor(kind string) string {
	switch kind {
	case "user":
		return "rgba(232,165,49,0.18)"
	case "assistant":
		return "rgba(109,201,122,0.18)"
	case "tool":
		return "rgba(232,165,49,0.08)"
	default:
		return "rgba(38,42,51,0.8)"
	}
}

func nodeStroke(kind string) string {
	switch kind {
	case "user":
		return "#e8a531"
	case "assistant":
		return "#6dc97a"
	default:
		return "#343844"
	}
}

func roleInitial(role string) string {
	if len(role) == 0 {
		return "?"
	}
	return strings.ToUpper(role[:1])
}

func shortHashDag(hash string) string {
	if len(hash) > 7 {
		return hash[:7]
	}
	return hash
}

